import React from 'react';
import { Outlet, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const SchedulerLayout = () => {
  const { logout, user } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#f3f4f6' }}>
      {/* Sidebar */}
      <div style={{ width: '250px', background: '#003366', color: 'white', display: 'flex', flexDirection: 'column', padding: '20px' }}>
        <h2 style={{ textAlign: 'center', marginBottom: '40px', letterSpacing: '1px' }}>SCHEDULER</h2>
        
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <Link to="/scheduler/tasks" style={linkStyle}>📋 Nhiệm vụ</Link>
        </div>

        <div style={{ borderTop: '1px solid rgba(255,255,255,0.2)', paddingTop: '20px' }}>
          <div style={{ fontSize: '0.9rem', marginBottom: '10px' }}>Hi, {user?.name}</div>
          <button onClick={handleLogout} style={logoutBtnStyle}>Đăng xuất</button>
        </div>
      </div>

      {/* Content */}
      <div style={{ flex: 1, padding: '30px', overflowY: 'auto' }}>
        <Outlet />
      </div>
    </div>
  );
};

const linkStyle = {
  color: 'white', textDecoration: 'none', padding: '12px', borderRadius: '8px',
  background: 'rgba(255,255,255,0.1)', display: 'block', fontWeight: '500'
};

const logoutBtnStyle = {
  background: '#ef4444', color: 'white', border: 'none', padding: '8px 15px',
  borderRadius: '4px', cursor: 'pointer', width: '100%', fontWeight: 'bold'
};

export default SchedulerLayout;
